"""Fallback competitor intel when Tavily Research output is missing or invalid."""from __future__ import annotationsimport refrom validation.schemas import (    CompetitorFinding,    CompetitorIntelItem,    CompetitorScanIntel,    IdeaWorksheet,)def _match_finding(name: str, findings: list[CompetitorFinding]) -> CompetitorFinding | None:    token = re.sub(r"[^a-z0-9]+", " ", name.lower()).strip()    if not token:        return None    for finding in findings:        hay = f"{finding.title} {finding.url} {finding.snippet}".lower()        if token in hay or token.split()[0] in hay:            return finding    return Nonedef _heuristic_intel(    worksheet: IdeaWorksheet,    findings: list[CompetitorFinding],) -> CompetitorScanIntel:    """ponytail: deterministic rows when research output is unusable."""    names = [c.strip() for c in worksheet.competitors if c.strip()] or [worksheet.working_name]    rows: list[CompetitorIntelItem] = []    matched = 0    for name in names:        hit = _match_finding(name, findings)        if hit:            matched += 1            rows.append(                CompetitorIntelItem(                    competitor=name,                    positioning=hit.snippet,                    gap_vs_us=None,                    source_url=hit.url,                    source_title=hit.title,                    signal_strength="weak",                )            )        else:            rows.append(                CompetitorIntelItem(                    competitor=name,                    positioning=f"No direct web hit for {name}. Check their pricing page and core PRD/docs features.",                    gap_vs_us=None,                    source_url=None,                    source_title=None,                    signal_strength="none",                )            )    if matched:        gap = (            f"Matched web sources for {matched} of {len(names)} named competitors. "            f"Edit positioning claims and add gaps before saving."        )    else:        gap = (            "Web research returned sources but none mapped cleanly to named competitors. "            "Open the links below and write one verifiable claim per competitor."        )    return CompetitorScanIntel(rows=rows, overall_gap=gap)def _scrub_intel_sources(    intel: CompetitorScanIntel,    findings: list[CompetitorFinding],) -> CompetitorScanIntel:    allowed = {f.url for f in findings}    rows: list[CompetitorIntelItem] = []    for row in intel.rows:        if row.source_url and row.source_url not in allowed:            rows.append(                row.model_copy(                    update={                        "source_url": None,                        "source_title": None,                        "signal_strength": "none",                    }                )            )        else:            rows.append(row)    return intel.model_copy(update={"rows": rows})